window.__QUIZ_DATA__=[{"id":"objective>Agricultural Science>2023>1","subject":"Agricultural Science","year":"2023","type":"Objective","topic":"AGRICULTURAL ECONOMICS AND EXTENSION : MARKETING OF AGRICULTURAL PRODUCE","question":"The storage structure usually installed by the government for bulk storage of grains in West Africa is","images":[],"options":{"A":"bin","B":"crib","C":"silo","D":"rhombus"},"answer":"C","explanation":"A silo is a storage structure that is commonly used for bulk storage of grains, such as rice, wheat, maize, and other agricultural products. It is often installed by governments and agricultural organizations to store large quantities of harvested grains for future use and to ensure food security.","marks":"1","difficulty":"1"},{"id":"objective>Agricultural Science>2023>2","subject":"Agricultural Science","year":"2023","type":"Objective","topic":"BASIC CONCEPTS : PROBLEMS OF AGRICULTURAL DEVELOPMENT AND POSSIBLE SOLUTIONS","question":"Rural-urban migration of farm labour could be prevented by","images":[],"options":{"A":"increasing the size of farmland for cultivation","B":"employing more extension agents for farmers.","C":"increasing the cost of acquiring farmland","D":"establishing agro-based industries in villages."},"answer":"D","explanation":"Establishing agro-based industries in villages can help prevent rural-urban migration of farm labor by providing additional job opportunities and income sources for the rural population. Agro-based industries are those that process and add value to agricultural products. By setting up such industries in villages, farmers and rural workers can find employment locally, reducing the need to migrate to cities in search of jobs.","marks":"1","difficulty":"2"},{"id":"objective>Agricultural Science>2023>3","subject":"Agricultural Science","year":"2023","type":"Objective","topic":"AGRICULTURAL ECOLOGY : LAND AND ITS USE","question":"The farming system generally recommended for farm settlement scheme is","images":[],"options":{"A":"mixed cropping","B":"pastoral farming","C":"mixed farming","D":"continuous cropping"},"answer":"C","explanation":"Mixed farming is the farming system generally recommended for farm settlement schemes. Mixed farming involves the cultivation of different crops and the rearing of various livestock on the same farm. It is a diversified farming approach where farmers grow crops and raise animals simultaneously.","marks":"1","difficulty":"2"},{"id":"objective>Agricultural Science>2023>4","subject":"Agricultural Science","year":"2023","type":"Objective","topic":"AGRICULTURAL ENGINEERING/MECHANIZATION : FARM MACHINERY AND IMPLEMENTS","question":"The part of a disc plough to which discs are connected is","images":[],"options":{"A":"scraper","B":"beam","C":"furrow wheel","D":"standard"},"answer":"D","explanation":"The standard is the part of the plough that holds the disc and allows it to rotate. It is the main support structure for the disc.","marks":"1","difficulty":"1"},{"id":"objective>Agricultural Science>2023>5","subject":"Agricultural Science","year":"2023","type":"Objective","topic":"AGRICULTURAL ENGINEERING/MECHANIZATION : FARM MACHINERY AND IMPLEMENTS","question":"A combine harvester is mainly used for harvesting","images":[],"options":{"A":"groundnut","B":"pepper","C":"rice","D":"tomato"},"answer":"C","explanation":"A combine harvester, also known as a combine, is mainly used for harvesting rice. A combine harvester is a versatile agricultural machine that combines several functions into one, making it efficient for harvesting various crops.","marks":"1","difficulty":"1"},{"id":"objective>Agricultural Science>2023>6","subject":"Agricultural Science","year":"2023","type":"Objective","topic":"AGRICULTURAL ENGINEERING/MECHANIZATION : FARM POWER","question":"The diagrams below illustrate different sources of farm power. Study them and answer the question.      Which of the illustrated sources of farm power is the cheapest","images":["data:image/png;base64,"],"options":{"A":"I","B":"II","C":"III","D":"IV"},"answer":"A","explanation":"I is the cheapest sources of farm power because it uses crude tool","marks":"1","difficulty":"3"},{"id":"objective>Agricultural Science>2023>7","subject":"Agricultural Science","year":"2023","type":"Objective","topic":"AGRICULTURAL ENGINEERING/MECHANIZATION : FARM POWER","question":"The diagrams below illustrate different sources of farm power. Study them and answer the question.    The machinery illustrated in diagram III could be used to power  I. planters  II. dryers  III. sprayers","images":["data:image/png;base64,"],"options":{"A":"I and II only.","B":"I and III only","C":"II and III only","D":"I, II and III"},"answer":"D","explanation":"I, II and III. The tractor can be used to power planters, dryers, and sprayers. Tractors are versatile and powerful agricultural machines that can perform various tasks on the farm, including planting, drying, and spraying.","marks":"1","difficulty":"3"},{"id":"objective>Agricultural Science>2023>8","subject":"Agricultural Science","year":"2023","type":"Objective","topic":"AGRICULTURAL ENGINEERING/MECHANIZATION : FARM POWER","question":"The diagrams below illustrate different sources of farm power. Study them and answer the question.    Which of the illustrated sources of farm power decrease in efficiency due to constant use?","images":["data:image/png;base64,"],"options":{"A":"I and II only.","B":"I and III only","C":"II and III only.","D":"I, II and III."},"answer":"D","explanation":"I, II and III will decrease in efficiency due to constant use","marks":"1","difficulty":"3"},{"id":"objective>Agricultural Science>2023>9","subject":"Agricultural Science","year":"2023","type":"Objective","topic":"ANIMAL PRODUCTION : ANIMAL HEALTH MANAGEMENT","question":"High relative humidity in a brooder house could lead to","images":[],"options":{"A":"heat stress","B":"reduced feed intake","C":"production of dry litter","D":"build up of pests and diseases"},"answer":"D","explanation":"High humidity in a brooder house creates a conducive environment for the growth and multiplication of pests and diseases. It can also lead to the development of mould and fungi, which can be harmful to the chicks.","marks":"1","difficulty":"2"},{"id":"objective>Agricultural Science>2023>10","subject":"Agricultural Science","year":"2023","type":"Objective","topic":"CROP PRODUCTION : HUSBANDRY OF SELECTED CROPS","question":"Day-neutral crops are crops that produce flowers regardless of","images":[],"options":{"A":"extremely low temperature","B":"daylength being longer than the length of night","C":"extremely high temperature","D":"amount of sunlight received by flowering plants."},"answer":"B","explanation":"Day-neutral crops, also known as non-photoperiodic crops, are plants that produce flowers independently of the daylength. Unlike short-day and long-day plants, which require specific daylength conditions to flower, day-neutral crops are not influenced by the length of the day or night.","marks":"1","difficulty":"2"},{"id":"objective>Agricultural Science>2023>11","subject":"Agricultural Science","year":"2023","type":"Objective","topic":"AGRICULTURAL ECOLOGY : TYPES, COMPOSITION AND PROPERTIES OF SOIL","question":"Which of the following tools are used in soil analysis?  I. pH meter  II. Sieve  III. Hygrometer","images":[],"options":{"A":"I and II only","B":"I and III only","C":"II and III only","D":"I, II and III"},"answer":"D","explanation":"All the tools listed are used in soil analysis. A pH meter is used to measure the acidity or alkalinity of the soil. A sieve is used to separate and grade soil and rock particles according to their size. A hygrometer is used to measure the moisture content in the atmosphere, which can affect soil moisture levels.","marks":"1","difficulty":"1"},{"id":"objective>Agricultural Science>2023>12","subject":"Agricultural Science","year":"2023","type":"Objective","topic":"AGRICULTURAL ECOLOGY : IRRIGATION","question":"If 200 ml of water was poured on a soil sample in a beaker and 25% of the water drained through the soil, determine the amount of water retained in the soil.","images":[],"options":{"A":"25 ml","B":"50 ml","C":"150 ml","D":"175 ml"},"answer":"C","explanation":"If 200 ml of water was poured onto a soil sample in a beaker and 25% of the water drained through the soil, it means that 75% of the water remains retained in the soil.    To find the amount of water retained in the soil, we can calculate 75% of the original 200 ml of water:    Amount of water retained = 0.75 (75%) * 200 ml = 150 ml    So, 150 ml of water is retained in the soil after 25% of the water has drained through.","marks":"1","difficulty":"2"},{"id":"objective>Agricultural Science>2023>13","subject":"Agricultural Science","year":"2023","type":"Objective","topic":"AGRICULTURAL ECOLOGY : TYPES, COMPOSITION AND PROPERTIES OF SOIL","question":"Soil structure is described as the","images":[],"options":{"A":"proportion of different sizes of soil particles.","B":"degree of soil aeration within the soil.","C":"arrangement of soil particles into aggregates","D":"degree of water percolation within the soil."},"answer":"C","explanation":"Soil structure refers to the way soil particles are organized and arranged into aggregates or clumps. It is an important characteristic of soil that influences various soil properties and processes, including water retention, aeration, root penetration, and nutrient availability.","marks":"1","difficulty":"1"},{"id":"objective>Agricultural Science>2023>14","subject":"Agricultural Science","year":"2023","type":"Objective","topic":"AGRICULTURAL ECOLOGY : AGRICULTURAL POLLUTION","question":"A beneficial effect of bush burning is that it","images":[],"options":{"A":"increases the population of soil microorganisms.","B":"encourages the regeneration of grasses","C":"increases the organic matter of soil.","D":"replenishes oxygen in the atmosphere"},"answer":"B","explanation":"When a controlled fire burns through a grassland, it can remove accumulated dead plant material and woody debris, known as thatch. Thatch can hinder the growth of new grass shoots and prevent sunlight and rainwater from reaching the soil surface. By removing the thatch through controlled burning, the fire creates a favorable environment for grass regeneration.","marks":"1","difficulty":"1"},{"id":"objective>Agricultural Science>2023>15","subject":"Agricultural Science","year":"2023","type":"Objective","topic":"AGRICULTURAL ECOLOGY : MEANING AND IMPORTANCE OF AGRICULTURAL ECOLOGY","question":"The diagram below illustrates a method of compost making. Study it and answer the question.     The method of compost milking illustrated in the diagram is","images":["data:image/png;base64,"],"options":{"A":"heap","B":"bin","C":"pit","D":"sheet"},"answer":"C","explanation":"The method of compost milking illustrated in the diagram is pit","marks":"1","difficulty":"2"},{"id":"objective>Agricultural Science>2023>16","subject":"Agricultural Science","year":"2023","type":"Objective","topic":"AGRICULTURAL ECOLOGY : MEANING AND IMPORTANCE OF AGRICULTURAL ECOLOGY","question":"The diagram below illustrates a method of compost making. Study it and answer the question.   The part labelled I is used for","images":["data:image/png;base64,"],"options":{"A":"turning the compost materials.","B":"checking the decomposition rate","C":"stacking the compost materials","D":"hastening the fermentation rate"},"answer":"A","explanation":"The part labelled I is used for turning the compost materials.","marks":"1","difficulty":"2"},{"id":"objective>Agricultural Science>2023>17","subject":"Agricultural Science","year":"2023","type":"Objective","topic":"AGRICULTURAL ECOLOGY : MEANING AND IMPORTANCE OF AGRICULTURAL ECOLOGY","question":"The diagram below illustrates a method of compost making. Study it and answer the question.   A material that could be used as starter in the method of compost making illustrated is","images":["data:image/png;base64,"],"options":{"A":"blood","B":"ash","C":"straw","D":"urine"},"answer":"D","explanation":"Urine can be used as a starter or compost activator in the method of compost making. Human urine is rich in nitrogen, which is an essential element for the composting process. Nitrogen is a key component that helps promote the growth and activity of beneficial microorganisms responsible for breaking down organic matter in the compost pile.","marks":"1","difficulty":"2"},{"id":"objective>Agricultural Science>2023>18","subject":"Agricultural Science","year":"2023","type":"Objective","topic":"AGRICULTURAL ECOLOGY : PLANT NUTRIENTS AND NUTRIENT CYCLE","question":"The bacterium which is responsible for conversion of ammonium compounds to nitrites in the nitrogen cycle is","images":[],"options":{"A":"Azotobacter","B":"Rhizobium","C":"Nitrosomonas","D":"Nitrobacter"},"answer":"C","explanation":"Nitrosomonas is the bacterium responsible for the first step in this conversion process, where it oxidizes ammonium compounds to nitrites. This conversion is essential as it prepares the nitrogen compounds for the subsequent steps in the nitrogen cycle.","marks":"1","difficulty":"2"},{"id":"objective>Agricultural Science>2023>19","subject":"Agricultural Science","year":"2023","type":"Objective","topic":"AGRICULTURAL ECOLOGY : DRAINAGE","question":"Which of the following statements about underground drainage is true?","images":[],"options":{"A":"Ditches are constructed to remove excess water","B":"Water seeps into tiles to reach an outlet where it is discharged","C":"Ditches are dug from a source of water to the farmland","D":"Furrows are constructed to direct water out of the farmland"},"answer":"B","explanation":"In this drainage system, perforated pipes or tiles are placed underground at a certain depth, usually below the root zone of the crops. These pipes or tiles have small holes or perforations that allow water to seep into them from the surrounding soil. As the water table rises due to excess moisture in the soil, the water seeps into these pipes through the perforations.","marks":"1","difficulty":"1"},{"id":"objective>Agricultural Science>2023>20","subject":"Agricultural Science","year":"2023","type":"Objective","topic":"CROP PRODUCTION : CLASSIFICATION OF CROPS","question":"Monocotyledonous crops are characterized by","images":[],"options":{"A":"net-veined leaves","B":"taproot system","C":"parallel-veined leaves","D":"woody stems and branches."},"answer":"C","explanation":"Monocotyledonous crops typically have leaves with parallel venation. This means that the veins in the leaf run parallel to each other, extending from the base to the tip of the leaf without forming a complex network. The parallel arrangement of veins is a key characteristic that sets monocots apart from dicotyledonous plants (dicots), which have net-veined leaves.","marks":"1","difficulty":"1"},{"id":"objective>Agricultural Science>2023>21","subject":"Agricultural Science","year":"2023","type":"Objective","topic":"AGRICULTURAL ECOLOGY : AGRO-ALLIED INDUSTRIES AND RELATIONSHIP BETWEEN AGRICULTURE AND INDUSTRY","question":"Maceration is carried out in the processing of","images":[],"options":{"A":"cocoa","B":"cotton","C":"oil palm","D":"paddy rice."},"answer":"C","explanation":"Maceration is a process used in the processing of oil palm. It involves the softening or breaking down of the oil palm fruits by soaking them in water or another liquid. This process helps to separate the oil from the fruit and makes it easier to extract the oil.","marks":"1","difficulty":"1"},{"id":"objective>Agricultural Science>2023>22","subject":"Agricultural Science","year":"2023","type":"Objective","topic":"CROP PRODUCTION : HUSBANDRY OF SELECTED CROPS","question":"If the seed rate for the cultivation of cowpea is 25 kg per hectare, determine the quantity of cowpea seeds required to cultivate a farmland measuring 100 m by 500 m.","images":[],"options":{"A":"50 kg","B":"125 kg","C":"250 kg","D":"1,250 kg"},"answer":"B","explanation":"1 hectare = 10,000 square meters  Area of the farmland = 100 m x 500 m = 50,000 square meters  Now, we can convert the area to hectares:  Area in hectares = 50,000 square meters / 10,000 square meters/hectare = 5 hectares  Next, we can calculate the quantity of cowpea seeds required using the given seed rate:  Seed rate = 25 kg/hectare  Quantity of cowpea seeds required = Seed rate x Area  Quantity of cowpea seeds required = 25 kg/hectare x 5 hectares  Quantity of cowpea seeds required = 125 kg  Therefore, the quantity of cowpea seeds required to cultivate the farmland is 125 kg. The correct answer is \"125 kg.\"","marks":"1","difficulty":"2"},{"id":"objective>Agricultural Science>2023>23","subject":"Agricultural Science","year":"2023","type":"Objective","topic":"CROP PRODUCTION : HUSBANDRY OF SELECTED CROPS","question":"Which of the following crops require a nursery?","images":[],"options":{"A":"Soya bean","B":"Cotton seed","C":"Yam","D":"Rubber"},"answer":"D","explanation":"Among the given options, 'Rubber' is the crop that requires a nursery. A nursery is a place where plants are propagated and grown to a desired age. Rubber seeds are usually sown in a nursery and the seedlings are transplanted to the field when they are about 6 months old.","marks":"1","difficulty":"1"},{"id":"objective>Agricultural Science>2023>24","subject":"Agricultural Science","year":"2023","type":"Objective","topic":"AGRICULTURAL ENGINEERING/MECHANIZATION : FARM MACHINERY AND IMPLEMENTS","question":"The diagram below illustrates a farm operation. Study it and answer the question      The illustrated farm operation is known as","images":["data:image/png;base64,"],"options":{"A":"threshing","B":"milling","C":"winnowing","D":"shelling"},"answer":"C","explanation":"Winnowing is the process of separating the lighter chaff or husk from the heavier grains or seeds after threshing. It is usually done by tossing the mixture of grains and chaff into the air with a winnowing basket or using a winnowing machine. The wind carries away the lighter chaff, allowing the heavier grains to fall back to the ground or into a container.","marks":"1","difficulty":"2"},{"id":"objective>Agricultural Science>2023>25","subject":"Agricultural Science","year":"2023","type":"Objective","topic":"CROP PRODUCTION : HUSBANDRY OF SELECTED CROPS","question":"The diagram below illustrates a farm operation. Study it and answer the question    Examples of crops which require the illustrated farm operation are","images":["data:image/png;base64,"],"options":{"A":"cowpea, millet and okro.","B":"pepper, rice and cowpea.","C":"rice, groundnut and millet.","D":"maize, pepper and tomato."},"answer":"C","explanation":"Examples of crops which require the illustrated farm operation are rice, groundnut and millet.  This process is known as winnowing. This is the method of separating the unpleasant husk from food. It is achieved by pouring the grains on a windy day, from a height, when the grains fall on the ground and the chaff is swept away.","marks":"1","difficulty":"2"},{"id":"objective>Agricultural Science>2023>26","subject":"Agricultural Science","year":"2023","type":"Objective","topic":"CROP PRODUCTION : HUSBANDRY OF SELECTED CROPS","question":"The reduction of three seedlings of maize to two plants per stand is referred to as","images":[],"options":{"A":"pruning","B":"thinning","C":"rogueing","D":"weeding"},"answer":"B","explanation":"Thinning refers to the process of reducing the number of seedlings in a plant stand to achieve proper spacing and optimum plant density. In the context of the question, thinning involves removing one out of three seedlings of maize, resulting in two plants remaining per stand.","marks":"1","difficulty":"1"},{"id":"objective>Agricultural Science>2023>27","subject":"Agricultural Science","year":"2023","type":"Objective","topic":"CROP PRODUCTION : HUSBANDRY OF SELECTED CROPS","question":"Seedlings are best transplanted in the field","images":[],"options":{"A":"late in the morning and late in the evening.","B":"at midday and at dusk","C":"early in the morning and late in the evening","D":"early in the morning and at midday"},"answer":"C","explanation":"Transplanting seedlings is a critical step in the cultivation of crops. To ensure successful transplanting and minimize stress on the seedlings, it is recommended to do it early in the morning or late in the evening.","marks":"1","difficulty":"1"},{"id":"objective>Agricultural Science>2023>28","subject":"Agricultural Science","year":"2023","type":"Objective","topic":"AGRICULTURAL ECOLOGY : PLANT NUTRIENTS AND NUTRIENT CYCLE","question":"Which of the following combinations of NPK fertilizer is recommended for the cultivation of yam and cassava?","images":[],"options":{"A":"10:10:10","B":"10:10:20","C":"20:10:10","D":"20:20:10"},"answer":"C","explanation":"For the cultivation of yam and cassava, the recommended NPK fertilizer ratio is 20:10:10. This means the fertilizer contains a higher percentage of nitrogen (N) compared to phosphorus (P) and potassium (K). Nitrogen is essential for promoting vegetative growth and leaf development, which is important for yam and cassava during their early stages of growth.","marks":"1","difficulty":"2"},{"id":"objective>Agricultural Science>2023>29","subject":"Agricultural Science","year":"2023","type":"Objective","topic":"CROP PRODUCTION : HUSBANDRY OF SELECTED CROPS","question":"Post-planting operations in cocoa plantation include  I. rogueing   II. stumping  III. mulching","images":[],"options":{"A":"I and II only.","B":"I and III only.","C":"II and III only","D":"I, II and III"},"answer":"D","explanation":"Post-planting operations in a cocoa plantation include rogueing, stumping, and mulching. Rogueing involves removing plants that are diseased or not growing properly. Stumping is the process of cutting back the tree to a short stump to encourage new growth. Mulching involves covering the soil around the plants with organic material to conserve moisture, suppress weeds, and improve soil fertility.","marks":"1","difficulty":"2"},{"id":"objective>Agricultural Science>2023>30","subject":"Agricultural Science","year":"2023","type":"Objective","topic":"CROP PRODUCTION : PASTURE AND FORAGE CROPS","question":"Examples of cover crops are","images":[],"options":{"A":"Centrosema pubescens and  Mucuna utilis","B":"Calopogonium mucunoides and  Gliricidia sepium .","C":"Moringa oleifera and  Imperata cylindrica","D":"Panicum maximum and  Pennisetum purpureum ."},"answer":"A","explanation":"Cover crops are plants that are primarily grown for the benefit of the soil rather than the crop yield. They are typically grown to suppress weeds, manage soil erosion, help build and improve soil fertility and quality, and control diseases and pests.  Centrosema pubescens and  Mucuna utilis are examples of cover crops. They are used to improve soil fertility and control weeds.","marks":"1","difficulty":"1"},{"id":"objective>Agricultural Science>2023>31","subject":"Agricultural Science","year":"2023","type":"Objective","topic":"FORESTRY : FOREST MANAGEMENT","question":"Which of the following products is not a primary forest product?","images":[],"options":{"A":"Timber","B":"Pulp","C":"Fuelwood","D":"Mushroom"},"answer":"B","explanation":"Pulp is a processed material derived from wood, whereas timber and fuelwood are directly harvested from forests, and mushrooms are fungi found in forest ecosystems.","marks":"1","difficulty":"2"},{"id":"objective>Agricultural Science>2023>32","subject":"Agricultural Science","year":"2023","type":"Objective","topic":"FORESTRY : AGRO-FORESTRY PRACTICES IN WEST AFRICA","question":"A major reason for encouraging afforestation in arid regions of West Africa is to","images":[],"options":{"A":"increase timber production for export","B":"provide shade for crops sin taungya farming.","C":"serve as windbreak to check desert encroachment","D":"serve as forest reserve for wildlife conservation."},"answer":"C","explanation":"Explanation:  Encouraging afforestation in arid regions of West Africa is primarily done to serve as a windbreak and check desert encroachment mitigating the impact of desertification and protecting fertile lands from wind erosion.","marks":"1","difficulty":"2"},{"id":"objective>Agricultural Science>2023>33","subject":"Agricultural Science","year":"2023","type":"Objective","topic":"ORNAMENTAL PLANTS :","question":"Ornamental plants are primarily cultivated to","images":[],"options":{"A":"serve as raw materials.","B":"provide fodder for livestock","C":"serve as mulching materials","D":"beautify the environment"},"answer":"D","explanation":"Ornamental plants are primarily cultivated for their aesthetic value and decorative purposes. They are grown and maintained to beautify the environment, whether in gardens, parks, landscapes, or indoor settings.","marks":"1","difficulty":"1"},{"id":"objective>Agricultural Science>2023>34","subject":"Agricultural Science","year":"2023","type":"Objective","topic":"CROP PROTECTION : PESTS OF CROPS","question":"Cotton stainer is an insect pest of","images":[],"options":{"A":"onion","B":"pepper","C":"okro","D":"cotton"},"answer":"D","explanation":"The cotton stainer is an insect pest of cotton plants. The cotton stainer is an insect pest that primarily affects cotton plants, causing damage to the seeds and leading to staining of the cotton fibers, impacting cotton yield and fiber quality.","marks":"1","difficulty":"1"},{"id":"objective>Agricultural Science>2023>35","subject":"Agricultural Science","year":"2023","type":"Objective","topic":"ANIMAL PRODUCTION : ANATOMY AND PHYSIOLOGY OF FARM ANIMALS","question":"The number of teats in the udder of a cow is","images":[],"options":{"A":"two","B":"four","C":"six","D":"eight"},"answer":"B","explanation":"The udder of a cow consists of four separate compartments, each corresponding to one teat. Each teat serves as an outlet for the milk produced in the corresponding compartment of the udder.","marks":"1","difficulty":"1"},{"id":"objective>Agricultural Science>2023>36","subject":"Agricultural Science","year":"2023","type":"Objective","topic":"ANIMAL PRODUCTION : ANIMAL REPRODUCTION","question":"The diagram below illustrates a reproductive process in a farm animal. Study it and answer the question.      The reproductive process illustrated by the diagram is","images":["data:image/png;base64,"],"options":{"A":"heat","B":"ovulation","C":"lactation","D":"gestation"},"answer":"D","explanation":"Gestation refers to the period of pregnancy or the time it takes for female animals, particularly livestock, to carry and develop their offspring before giving birth.","marks":"1","difficulty":"2"},{"id":"objective>Agricultural Science>2023>37","subject":"Agricultural Science","year":"2023","type":"Objective","topic":"ANIMAL PRODUCTION : ANIMAL REPRODUCTION","question":"The diagram below illustrates a reproductive process in a farm animal. Study it and answer the question.    The parts which protect the foetus from mechanical injury are labelled","images":["data:image/png;base64,"],"options":{"A":"I and II","B":"I and III.","C":"II and III","D":"III and IV"},"answer":"A","explanation":"The parts which protect the foetus from mechanical injury are labelled I and II","marks":"1","difficulty":"2"},{"id":"objective>Agricultural Science>2023>38","subject":"Agricultural Science","year":"2023","type":"Objective","topic":"ANIMAL PRODUCTION : ANIMAL REPRODUCTION","question":"The diagram below illustrates a reproductive process in a farm animal. Study it and answer the question.    The foetus obtains dissolved oxygen and nutrients from the dam through the parts labelled","images":["data:image/png;base64,"],"options":{"A":"I and II.","B":"I and III","C":"II and III.","D":"III and IV"},"answer":"D","explanation":"The foetus obtains dissolved oxygen and nutrients from the dam through the parts labelled III and IV","marks":"1","difficulty":"2"},{"id":"objective>Agricultural Science>2023>39","subject":"Agricultural Science","year":"2023","type":"Objective","topic":"ANIMAL PRODUCTION : ANIMAL REPRODUCTION","question":"Assuming a sow was serviced on May 1 and conceived the same day, the expected date of parturition is","images":[],"options":{"A":"June 2","B":"August 24","C":"October 2","D":"September 30"},"answer":"D","explanation":"The gestation period for a sow (female pig) is approximately 3 months, 3 weeks, and 3 days, which is equivalent to about 114 days.  If the sow was serviced (mated) on May 1, we can calculate the expected date of parturition (giving birth) as follows:  Count 3 months from May 1: May + 3 months = August 1  Count 3 weeks from August 1: August 1 + 3 weeks = August 22  Count 3 more days from August 22: August 22 + 3 days = August 25  So, based on the gestation period, the expected date of parturition is around August 25. However, since not all months have the same number of days, we need to adjust for the extra days to reach the actual parturition date.  Counting from August 25 to September 30, there are 36 days (25 days in August and 5 days in September). Adding these 36 days to August 25:  August 25 + 36 days = September 30  Therefore, the expected date of parturition is September 30.","marks":"1","difficulty":"2"},{"id":"objective>Agricultural Science>2023>40","subject":"Agricultural Science","year":"2023","type":"Objective","topic":"ANIMAL PRODUCTION : LIVESTOCK MANAGEMENT","question":"In a poultry farm, 2,000 birds were laying an average of 1,680 eggs per day. Use this information to answer the question    What is the percentage of birds that did not lay eggs?","images":[],"options":{"A":"16%","B":"19%","C":"46%","D":"84%"},"answer":"A","explanation":"Number of birds that did not lay eggs = Total number of birds - Number of eggs laid  Given information:  Total number of birds = 2,000  Number of eggs laid = 1,680 per day  Number of birds that did not lay eggs = 2,000 - 1,680 = 320  Now, we can calculate the percentage of birds that did not lay eggs:  Percentage of birds that did not lay eggs = (Number of birds that did not lay eggs / Total number of birds) x 100  Percentage of birds that did not lay eggs = (320 / 2,000) x 100 = 0.16 x 100 = 16%  Therefore, the percentage of birds that did not lay eggs on that particular day is 16%.","marks":"1","difficulty":"2"},{"id":"objective>Agricultural Science>2023>41","subject":"Agricultural Science","year":"2023","type":"Objective","topic":"ANIMAL PRODUCTION : LIVESTOCK MANAGEMENT","question":"In a poultry farm, 2,000 birds were laying an average of 1,680 eggs per day. Use this information to answer the questionIf an egg tray contains 30 eggs, how many trays of eggs will be collected in one week?","images":[],"options":{"A":"240","B":"286","C":"392","D":"526"},"answer":"C","explanation":"Total number of birds = 2,000  Number of eggs laid per day = 1,680  Number of eggs laid in 7days = 1,680 x 7 =11760  Number of eggs in one tray = 30  x =11760/30  =392 trays","marks":"1","difficulty":"2"},{"id":"objective>Agricultural Science>2023>42","subject":"Agricultural Science","year":"2023","type":"Objective","topic":"ANIMAL PRODUCTION : ANIMAL NUTRITION","question":"Steaming up ration should be fed to","images":[],"options":{"A":"breeding female animals.","B":"weaned young animals","C":"lactating animals","D":"pregnant animals"},"answer":"D","explanation":"Steaming up ration is a special diet given to pregnant animals, especially cows, in the last few weeks before calving. It is designed to provide the necessary nutrients to the animal and the unborn calf, and to prepare the cow for lactation. Therefore, the correct answer is 'pregnant animals'.","marks":"1","difficulty":"1"},{"id":"objective>Agricultural Science>2023>43","subject":"Agricultural Science","year":"2023","type":"Objective","topic":"ANIMAL PRODUCTION : ANIMAL HEALTH MANAGEMENT","question":"Which of the following pairs of livestock diseases could be contracted through inhalation?","images":[],"options":{"A":"Anthrax and tuberculosis","B":"Newcastle disease and aspergillosis","C":"Coccidiosis and rinderpest","D":"Gumboro and brucellosis"},"answer":"B","explanation":"Newcastle disease and aspergillosis are livestock diseases that can be contracted through inhalation of infectious agents.","marks":"1","difficulty":"2"},{"id":"objective>Agricultural Science>2023>44","subject":"Agricultural Science","year":"2023","type":"Objective","topic":"ANIMAL PRODUCTION : AQUACULTURE","question":"Which of the following paring enterprise could best be combined with fish farming for mutual benefits?  I. Vegetable production  II. Beekeeping   III. Poultry production","images":[],"options":{"A":"I and II only","B":"I and III only","C":"II and III only","D":"I, II and III"},"answer":"B","explanation":"Fish farming can be combined with vegetable production and poultry production for mutual benefits. The waste from the fish can be used as fertilizer for the vegetables, and the vegetables can help filter the water for the fish. Similarly, poultry droppings can serve as a source of food for the fish, and the fish waste can be used as a source of protein for the poultry. Therefore, the correct answer is 'I and III only'.","marks":"1","difficulty":"2"},{"id":"objective>Agricultural Science>2023>45","subject":"Agricultural Science","year":"2023","type":"Objective","topic":"ANIMAL PRODUCTION : APICULTURE OR BEE KEEPING","question":"A pest of honeybee is","images":[],"options":{"A":"tick","B":"grasshopper","C":"lizard","D":"bird"},"answer":"D","explanation":"A pest of honeybees is a creature or organism that poses a threat or causes harm to honeybee colonies or individual honeybees. Among the options provided,  bird is considered a pest of honeybees due to their predation behaviour. While lizards might occasionally eat a bee if they come across one, they are not considered a significant threat or pest to honey bee colonies. Their impact on bee populations is minimal and incidental.","marks":"1","difficulty":"1"},{"id":"objective>Agricultural Science>2023>46","subject":"Agricultural Science","year":"2023","type":"Objective","topic":"AGRICULTURAL ENGINEERING/MECHANIZATION : MAINTENANCE PRACTICES AND PRECAUTIONARY MEASURES","question":"Study the table below and use it to answer the question  Cost Price(N)Useful life(Years)Salvage value (N)Annual depreciation(N)Total depreciation20000Y50001000 annum150006000010180004200annumZ    The useful life represented by Y in the illustrated table is","images":[],"options":{"A":"3 years","B":"4 years","C":"15 years","D":"20 years"},"answer":"C","explanation":"Cost Price (N) = 20000  Salvage value (N) = 5000  Annual depreciation (N) = 1000  Total depreciation = 15000  The formula to calculate the useful life is:  Useful life = (Cost Price - Salvage value) / Annual depreciation  Now, let's plug in the values:  Useful life = (20000 - 5000) / 1000  Useful life = 15000 / 1000  Useful life = 15 years  Therefore, the useful life represented by Y in the table is 15 years.","marks":"1","difficulty":"3"},{"id":"objective>Agricultural Science>2023>47","subject":"Agricultural Science","year":"2023","type":"Objective","topic":"AGRICULTURAL ENGINEERING/MECHANIZATION : MAINTENANCE PRACTICES AND PRECAUTIONARY MEASURES","question":"Study the table below and use it to answer the question  Cost Price(N)Useful life(Years)Salvage value (N)Annual depreciation(N)Total depreciation20000Y50001000 annum150006000010180004200annumZThe total depreciation represented by Z in the illustrated table is","images":[],"options":{"A":"N 22,200","B":"N 42,000","C":"N 55.800","D":"N78,000"},"answer":"B","explanation":"ost Price (N) = 60000  Salvage value (N) = 18000  Annual depreciation (N) = 4200  Useful life (Years) = 10  The formula to calculate the total depreciation is:  Total depreciation = (Cost Price - Salvage value) / Useful life  Now, let's plug in the values:  Total depreciation = (60000 - 18000) / 10  Total depreciation = 42000 / 10  Total depreciation = 4200  Therefore, the total depreciation represented by Z in the table is N 42,000.","marks":"1","difficulty":"3"},{"id":"objective>Agricultural Science>2023>48","subject":"Agricultural Science","year":"2023","type":"Objective","topic":"AGRICULTURAL ECONOMICS AND EXTENSION : MARKETING OF AGRICULTURAL PRODUCE","question":"Grading of farm produce is important because it","images":[],"options":{"A":"maintains produce quality","B":"prolongs storability","C":"facilitates transportation","D":"facilitates pricing"},"answer":"D","explanation":"Grading allows farm produce to be classified into different grades based on their quality attributes. Each grade can then be assigned a specific price point, reflecting its quality and market demand. This transparent pricing system benefits both producers and consumers.","marks":"1","difficulty":"1"},{"id":"objective>Agricultural Science>2023>49","subject":"Agricultural Science","year":"2023","type":"Objective","topic":"AGRICULTURAL ECONOMICS AND EXTENSION : AGRICULTURAL INSURANCE","question":"The risk of production in agricultural business is borne by the","images":[],"options":{"A":"farm assistant","B":"farm labour","C":"farm owner","D":"farmer's family"},"answer":"C","explanation":"Farm owner is the one who bears the risk of production in agricultural business, as they have the ultimate responsibility for the business's success or failure and make critical decisions that impact the farm's performance and profitability.","marks":"1","difficulty":"1"},{"id":"objective>Agricultural Science>2023>50","subject":"Agricultural Science","year":"2023","type":"Objective","topic":"AGRICULTURAL ECONOMICS AND EXTENSION : AGRICULTURAL EXTENSION","question":"In order to backup extension messages, an extension agent should","images":[],"options":{"A":"procure agricultural loans for farmers","B":"provide marketing channels for farmers.","C":"assist farmers in locating sources of farm inputs.","D":"provide modern machines to farmers"},"answer":"C","explanation":"Assisting farmers in locating sources of farm inputs is the most relevant option for an extension agent to back up extension messages. This support ensures that farmers can implement the recommended practices effectively and achieve better agricultural outcomes.","marks":"1","difficulty":"2"}];